import os, re, json, urllib.request; env = open('.env').read(); url = re.search(r'VITE_SUPABASE_URL="(.*?)"', env).group(1); key = re.search(r'VITE_SUPABASE_PUBLISHABLE_KEY="(.*?)"', env).group(1); req = urllib.request.Request(url + '/rest/v1/planejamento_cache?select=*&limit=1', headers={'apikey': key, 'Authorization': 'Bearer ' + key}); res = urllib.request.urlopen(req); data = json.loads(res.read()); print(data);
